import jsPDF from 'jspdf'
import autoTable from 'jspdf-autotable'
import type { BillingRecord, SubscriptionPlan } from '../types'
import { getCompanySettings, getTaxSettings } from './settingsService'

const formatCurrency = (amount: number, currencySymbol: string) => {
  return `${currencySymbol}${amount.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`
}

export const downloadSubscriptionInvoicePDF = (
  record: BillingRecord,
  plan: SubscriptionPlan
): void => {
  const company = getCompanySettings()
  const taxSettings = getTaxSettings()
  const doc = new jsPDF()

  const currencySymbol = company.currencySymbol || '₹'
  const invoiceDate = record.billingDate ? new Date(record.billingDate) : new Date()
  const planName = plan.name

  doc.setFontSize(16)
  doc.text(company.companyName || 'Company', 14, 18)
  doc.setFontSize(10)
  doc.text(company.address || '', 14, 24)
  doc.text(`${company.city || ''} ${company.state || ''} ${company.pincode || ''}`, 14, 29)
  doc.text(company.email || '', 14, 34)
  doc.text(company.phone || '', 14, 39)

  doc.setFontSize(14)
  doc.text('Subscription Invoice', 150, 18, { align: 'right' })
  doc.setFontSize(10)
  doc.text(`Invoice #: ${record.invoiceNumber || 'N/A'}`, 150, 24, { align: 'right' })
  doc.text(`Date: ${invoiceDate.toLocaleDateString('en-IN')}`, 150, 29, { align: 'right' })

  const gstEnabled = !!(company.gstin || taxSettings.gstin)
  const taxRate = gstEnabled ? (record.taxRate ?? 0.18) : 0
  const baseAmount = record.amount || 0
  const taxAmount = record.taxAmount ?? Math.round(baseAmount * taxRate * 100) / 100
  const totalAmount = baseAmount + taxAmount

  autoTable(doc, {
    startY: 48,
    head: [['Item', 'Billing Cycle', 'Amount']],
    body: [[
      planName,
      record.billingCycle || 'monthly',
      formatCurrency(baseAmount, currencySymbol)
    ]]
  })

  const summaryStart = (doc as any).lastAutoTable.finalY + 8
  doc.setFontSize(11)
  doc.text('Summary', 14, summaryStart)
  doc.setFontSize(10)
  doc.text(`Subtotal: ${formatCurrency(baseAmount, currencySymbol)}`, 14, summaryStart + 6)
  if (taxRate > 0) {
    doc.text(`GST (${Math.round(taxRate * 100)}%): ${formatCurrency(taxAmount, currencySymbol)}`, 14, summaryStart + 12)
  }
  doc.text(`Total: ${formatCurrency(totalAmount, currencySymbol)}`, 14, summaryStart + 18)

  doc.setFontSize(9)
  doc.text('This is a system generated subscription invoice.', 14, summaryStart + 30)

  doc.save(`Subscription-Invoice-${record.invoiceNumber || Date.now()}.pdf`)
}
